SELECT sample_desc, geolocation
FROM samples
WHERE storage_location = 'Lab A Freezer' AND input_type = 'Illumina paired-end';

SELECT s.sample_desc || ' ' || it.input_type_name AS sample_input
FROM samples s
JOIN input_types it ON s.input_type = it.input_type_name;

SELECT sample_id, storage_location
FROM samples
WHERE (SELECT AVG(quality_score) FROM samples) > 0.92;

SELECT s.sample_id, si.site_name, si.location 
FROM samples s
LEFT JOIN sites si ON s.site_id = si.site_id;

SELECT COUNT(*) 
FROM samples 
WHERE quality_score > (SELECT AVG(quality_score) FROM samples);

SELECT MAX(annotation_date) AS most_recent_annotation_date
FROM annotations
WHERE sample_id = '1';

SELECT DISTINCT user_name
FROM users
WHERE permissions LIKE '%read%' OR permissions LIKE '%write%';

SELECT sample_id, sample_desc, strain, genus, species, input_type, trim, site_id, project_id, created_at, updated_at, collection_date, isolation_source, geolocation, quality_score, public_access, storage_location
FROM samples
WHERE site_id = 1 AND collection_date BETWEEN '2020-01-01' AND '2022-12-31';

SELECT DISTINCT sample_id 
FROM samples 
WHERE trim = 'yes';

SELECT DISTINCT sample_id
FROM annotations
WHERE annotation_text LIKE '%complete%';

SELECT step_name, step_description 
FROM data_processing_steps 
WHERE sample_id = '1';
